import React from "react"
import ucsfLogo from './images/ucsfHealth.jpg'

const customStyles = {

    control: css => ({
    ...css,
    width: 400,
    }),
    menu: ({ width, ...css }) => ({
    ...css,
    width: '400px',
    minWidth: '20%',
    }),
    option: css => ({ ...css, width: 370 }),

}

const desktopTopStyle = {
    width: "100%", backgroundColor: "#052049", color: "#ffffff", height: "40px", fontSize: "14px"
  }


class Main extends React.Component {

    constructor(props) {
        super(props);
        this.state = { 
        };
    }


    componentDidMount() {

        this.setState({screen: 1});


        /*
        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `navi/getarea`

        fetch(backUrl, {
        "method": "GET",
        headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({result: response})
            this.setState({screen: 1})
            this.setState({selectedMain: null})
            this.setState({selectedSub: null})
            this.setState({selectedSubChild: null})
            //this.setState({subLocation: []})
            //this.setState({subLocationChildren: []})
        })
        .catch(err => {
        console.log(err);
        });
        */

    }




    render() {

        var header = "Loading ..."
        var content = []

        if (this.state.screen == 1) { 
            header = ""

            content.push(<div style={desktopTopStyle}><span style={{left: "30px", top: "10px", position: "relative"}}>University of California San Francisco</span></div>)
            content.push(<div style={{width: "100%", height: "100px", boxShadow: "0px 0px 8px 2px #CCCCCC"}}>
                <div style={{marginLeft: "4%"}}>
                    <div style={{float: "left", display: "grid", height: "100px"}}><img src={ucsfLogo} style={{height: "30px",  margin: "auto"}}></img></div>
                    <div style={{float: "left", marginLeft: "30px", fontFamily: "Arial", fontSize: "18px", height: "100px", display: "grid"}}><span style={{margin: "auto"}}>- Clinical Communications</span></div>
                </div>
                </div>)

                content.push(<div style={{marginTop: "50px", marginLeft: "100px"}}>
                    <div style={{float: "left", display: "grid"}}>
                        <div style={{backgroundColor: "#005588", width: "180px", height: "30px", color: "#FFFFFF", display: "grid"}}><span style={{margin: "auto", fontWeight: "normal"}}>Voalte</span>
                        </div>
                        <div>
                            <ul >
                                <li  style={{padding: "2px"}}><a href="https://applet.ucsfmedicalcenter.org/voalteInformation" target="_blank">Update Phone</a></li>
                                <li  style={{padding: "2px"}}><a href="https://applet.ucsfmedicalcenter.org/voalte" target="_blank">Last Login</a></li>
                                <li  style={{padding: "2px"}}><a href="https://applet.ucsfmedicalcenter.org/voaltedown" target="_blank">Down Time</a></li>
                                <li  style={{padding: "2px"}}><a href="https://applet.ucsfmedicalcenter.org/voalteFamilyReport" target="_blank">Voalte Family Report</a></li>
                            </ul>
                        </div>

                    </div>
                    <div style={{float: "left", display: "grid", marginLeft: "100px"}}>
                        <div style={{backgroundColor: "#CC6611", width: "180px", height: "30px", color: "#FFFFFF", display: "grid"}}><span style={{margin: "auto", fontWeight: "normal"}}>Hardware</span>
                        </div>
                        <div>
                            <ul >
                                <li  style={{padding: "2px"}}><a href="https://app.ucsfmedicalcenter.org/devices" target="_blank">Device tracking</a></li>
                            </ul>
                        </div>

                    </div>
                    <div style={{float: "left", display: "grid", marginLeft: "100px"}}>
                        <div style={{backgroundColor: "#CC9933", width: "180px", height: "30px", color: "#FFFFFF", display: "grid"}}><span style={{margin: "auto", fontWeight: "normal"}}>Connexall</span>
                        </div>
                        <div>
                            <ul >
                                <li  style={{padding: "2px"}}><a href="https://app.ucsfmedicalcenter.org/workflow" target="_blank">Code Activations</a></li>
                            </ul>
                        </div>

                    </div>




                </div>)


        }




        return (
            <div style={{minHeight: "500px", marginLeft: "0px", marginRight: "0px"}}>{content}<h2 className="display-4 text-center" style={{padding: "25px"}}>{header}</h2>
            </div>
        );
    }







}


export default Main
